package main
import ("bufio";"encoding/json";"fmt";"os";"path/filepath";"regexp";"strings")
type UserMeta struct { Username string `json:"username"`; Protocol string `json:"protocol"`; Secret string `json:"secret"`; Expired string `json:"expired"`; Status string `json:"status"`; IPLimit int `json:"iplimit"`; Violations int `json:"violations"` }
func loadUsers(root string) map[string]*UserMeta { out:=map[string]*UserMeta{}; filepath.Walk(root, func(path string, info os.FileInfo, err error) error { if err!=nil || info==nil || info.IsDir() || !strings.HasSuffix(path, ".json"){ return nil }; b,err:=os.ReadFile(path); if err!=nil { return nil }; var u UserMeta; if json.Unmarshal(b,&u)==nil { out[u.Username]=&u }; return nil }); return out }
func main(){ users:=loadUsers("/etc/katsu/users"); if len(users)==0 { return }; f,err:=os.Open("/var/log/xray/access.log"); if err!=nil { return }; defer f.Close(); re:=regexp.MustCompile(`tcp:([0-9]+\.[0-9]+\.[0-9]+\.[0-9]+):[0-9]+.*email: ([^ ]+)`); active:=map[string]map[string]bool{}; s:=bufio.NewScanner(f); for s.Scan(){ m:=re.FindStringSubmatch(s.Text()); if len(m)<3 { continue }; ip,user:=m[1],m[2]; if _,ok:=active[user]; !ok { active[user]=map[string]bool{} }; active[user][ip]=true }; changed:=false; for _,u:=range users { if u.Protocol=="ssh" { continue }; ips:=0; if x,ok:=active[u.Username]; ok { ips=len(x) }; if u.IPLimit>0 && ips>u.IPLimit { u.Violations++; u.Status="suspended"; changed=true; os.MkdirAll("/var/log/katsu",0755); f2,_:=os.OpenFile("/var/log/katsu/activity.log", os.O_CREATE|os.O_WRONLY|os.O_APPEND,0644); fmt.Fprintf(f2, "%s | %s | iplimit_exceeded | %d>%d\n", u.Username,u.Protocol,ips,u.IPLimit); f2.Close() } }; if changed { for _,u:=range users { path:=fmt.Sprintf("/etc/katsu/users/%s/%s.json", u.Protocol,u.Username); b,_:=json.MarshalIndent(u,"","  "); os.WriteFile(path,b,0644) } } }
